+    fs::create_dir_all(&nested_dir).expect("create nested repo dir");
+    fs::create_dir_all(&caller_dir).expect("create caller dir");
+    fs::write(
+        workspace_root.join(".bv/workspace.yaml"),
+        "repos:\n  - path: services/api\n",
